//! Feature-gated smoke checks executed by headless QEMU CI.

use alloc::{boxed::Box,string::String,vec::Vec};use core::arch::asm;use crate::{address_space,gdt,heap,keyboard,memory,process,serial,syscall,syscall_arch,syscall_entry};
#[cfg(feature="m0-smoke")]pub fn run_nonfatal(){heap_smoke();frame_reclamation_smoke();keyboard_smoke();user_descriptor_smoke();process_foundation_smoke();syscall_dispatch_smoke();syscall_entry_smoke();syscall_arch_smoke();serial::info(format_args!("m0-smoke: heap keyboard memory passed"));}
#[cfg(not(feature="m0-smoke"))]pub fn run_nonfatal(){}
#[cfg(feature="m0-smoke")]fn heap_smoke(){let before=heap::stats();let boxed=Box::new(0xa10a_05u64);let values=Vec::from([3u64,5,8,13]);let text=String::from("ALOHA-M0");assert_eq!(*boxed,0xa10a_05);assert_eq!(values.iter().copied().sum::<u64>(),29);assert_eq!(text.as_bytes(),b"ALOHA-M0");assert!(heap::stats().used>before.used);drop((boxed,values,text));serial::info(format_args!("m0-smoke: heap passed"));}
#[cfg(feature="m0-smoke")]fn frame_reclamation_smoke(){let frame=memory::allocate_frame().unwrap();assert!(unsafe{memory::deallocate_frame(frame)});assert_eq!(memory::allocate_frame().unwrap(),frame);serial::info(format_args!("m0-smoke: frame reclamation passed"));}
#[cfg(feature="m0-smoke")]fn keyboard_smoke(){keyboard::reset_decoder_for_smoke();assert!(matches!(keyboard::decode(0x10),Some(keyboard::Key::Character(b'q'))));assert!(keyboard::decode(0x2a).is_none());assert!(matches!(keyboard::decode(0x1e),Some(keyboard::Key::Character(b'A'))));assert!(keyboard::decode(0xaa).is_none());assert!(matches!(keyboard::decode(0x1c),Some(keyboard::Key::Enter)));serial::info(format_args!("m0-smoke: keyboard decode passed"));}
#[cfg(feature="m0-smoke")]fn user_descriptor_smoke(){assert_eq!(gdt::user_data_selector(),0x1b);assert_eq!(gdt::user_code_selector(),0x23);assert_ne!(gdt::rsp0(),0);serial::info(format_args!("m1-smoke: ring3 descriptors and rsp0 passed"));}
#[cfg(feature="m0-smoke")]fn process_foundation_smoke(){let before=memory::stats().allocated;let mut p=process::Process::new(7).unwrap();assert_eq!(p.kernel_stack_top()&0xf,0);let data=p.user_stack_top-memory::FRAME_SIZE;p.address_space.copy_to_user(data,b"ALOHA").unwrap();let mut copied=[0u8;5];p.address_space.copy_from_user(&mut copied,data).unwrap();assert_eq!(&copied,b"ALOHA");assert_eq!(p.address_space.copy_to_user(p.entry,b"X"),Err(address_space::UserAccessError::NotWritable));p.exit(42);drop(p);assert_eq!(memory::stats().allocated,before);serial::info(format_args!("m1-smoke: CR3 process user-copy lifecycle passed"));}
#[cfg(feature="m0-smoke")]fn syscall_dispatch_smoke(){let mut p=process::Process::new(9).unwrap();let data=p.user_stack_top-memory::FRAME_SIZE;let code=p.entry;p.address_space.copy_to_user(data,b"syscall").unwrap();assert_eq!(syscall::dispatch(&mut p,syscall::SYS_WRITE,[data,7,0,0,0,0]).value,7);assert_eq!(syscall::dispatch(&mut p,syscall::SYS_WRITE,[code,999,0,0,0,0]).value,syscall::Errno::TooLarge.encoded());assert_eq!(syscall::dispatch(&mut p,syscall::SYS_SLEEP,[1,0,0,0,0,0]).value,0);assert!(syscall::dispatch(&mut p,syscall::SYS_EXIT,[23,0,0,0,0,0]).terminated);serial::info(format_args!("m1-smoke: syscall ABI write exit sleep passed"));}
#[cfg(feature="m0-smoke")]fn syscall_entry_smoke(){let f=syscall_entry::UserReturnFrame{rip:process::USER_CODE_BASE,rsp:process::USER_STACK_TOP-16,rflags:0x202};assert_eq!(f.return_path(),syscall_entry::ReturnPath::Sysret);assert!(syscall_entry::cpu_supports_syscall());serial::info(format_args!("m1-smoke: syscall entry stack and return validation passed"));}
#[cfg(feature="m0-smoke")]fn syscall_arch_smoke(){assert!(syscall_arch::configuration_valid());let mut p=process::Process::new(10).unwrap();syscall_arch::install_process(&mut p);assert_eq!(syscall_arch::active_kernel_stack(),p.kernel_stack_top());syscall_arch::uninstall_process();serial::info(format_args!("m1-smoke: syscall MSRs and context dispatch passed"));}
#[cfg(feature="ring3-smoke")]pub fn run_ring3()->!{const M:u32=0xa10a_0033;let image=[0xb8,(M&0xff)as u8,((M>>8)&0xff)as u8,((M>>16)&0xff)as u8,((M>>24)&0xff)as u8,0xcd,0x80,0x0f,0x0b];let mut p=process::Process::new(33).unwrap();assert!(p.load_bootstrap_image(&image));serial::info(format_args!("ring3-smoke: entering user mode"));assert_eq!(crate::user_mode::run(&mut p),M as u64);serial::info(format_args!("ring3-smoke: user iretq rsp0 trap passed"));crate::halt()}
#[cfg(feature="syscall-smoke")]pub fn run_syscall()->!{let mut p=process::Process::new(44).unwrap();let message=p.user_stack_top-memory::FRAME_SIZE;p.address_space.copy_to_user(message,b"SYSCALL").unwrap();let mut image=[0u8;36];let mut i=0;macro_rules! emit{($($byte:expr),*$(,)?)=>{$(image[i]=$byte;i+=1;)*};}emit!(0xb8,1,0,0,0,0x48,0xbf);for b in message.to_le_bytes(){image[i]=b;i+=1;}emit!(0xbe,7,0,0,0,0x0f,0x05,0xb8,2,0,0,0,0xbf,42,0,0,0,0x0f,0x05,0x0f,0x0b);assert_eq!(i,image.len());assert!(p.load_bootstrap_image(&image));serial::info(format_args!("syscall-smoke: entering real syscall path"));let marker=crate::user_mode::run(&mut p);assert_eq!(marker,u64::MAX);assert_eq!(p.state,process::ProcessState::Exited);assert_eq!(p.exit_code,42);serial::info(format_args!("syscall-smoke: write and exit passed"));crate::halt()}
#[cfg(feature="exception-smoke")]pub fn trigger_exception()->!{serial::info(format_args!("exception-smoke: triggering breakpoint"));unsafe{asm!("int3",options(nomem,nostack))};panic!("breakpoint handler returned")}
#[cfg(not(feature="exception-smoke"))]pub fn trigger_exception(){}
